var e=[{id:`L3_1`,type:`dialog`,speaker:`MAX_CHARADE_NPC_CAP`,text:{KOREA:`제기랄!! 이런 망신을 당하다니!!`,JPN:`くそ！！　恥かかせやがって！！`,ENG:`Dammit!! That was humiliating!!`,TWN:`該死！！真是丟人現眼！！`},stage:{bg:`CORRIDOR_04`,slots:{L:null,C:{char_id:`MAX_CHARADE_NPC_CAP`,face:`UNIT_IDLE`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`MAX_CHARADE_NPC_CAP`,text:{KOREA:`아직 녀석들은 함선 안에 있을 거다!! 빨리 서둘러!!`,JPN:`まだ奴らは艦船の中にいるはずだ！！　急げ！！`,ENG:`Quick!! Those brats have to be inside that ship!!`,TWN:`她們一定還在艦船裡！！動作快！！`},stage:{bg:`CORRIDOR_04`,slots:{L:null,C:{char_id:`MAX_CHARADE_NPC_CAP`,face:`UNIT_IDLE`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`MAX_CHARADE_NPC_CAP`,text:{KOREA:`쥐새끼 한 마리도 빠져나가지 못하도록 철저하게 포위해!`,JPN:`ネズミ一匹逃げられないように、徹底的に包囲しろ！`,ENG:`Surround them and don't let a single rat get away!`,TWN:`一個都不准放過，全都給我抓起來！`},stage:{bg:`CORRIDOR_04`,slots:{L:null,C:{char_id:`MAX_CHARADE_NPC_CAP`,face:`UNIT_IDLE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`MAX_CHARADE_NPC_MOB`,text:{KOREA:`대장님! 열렸습니다!`,JPN:`隊長！　開きました！`,ENG:`Leader! It's open!`,TWN:`隊長！門開了！`},stage:{bg:`CORRIDOR_04`,slots:{L:{char_id:`MAX_CHARADE_NPC_MOB`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L13_1`,type:`dialog`,speaker:`MAX_CHARADE_NPC_CAP`,text:{KOREA:`좋아! 카운터의 공격을 주의하면서 단숨에 돌입한다!!`,JPN:`よし！　カウンターの攻撃に注意しながら、一気に突入するぞ！！`,ENG:`Okay! Watch out for the Counter and breach at once!!`,TWN:`很好！衝進去！！但要注意制裁者的攻擊！`},stage:{bg:`CORRIDOR_04`,slots:{L:null,C:{char_id:`MAX_CHARADE_NPC_CAP`,face:`UNIT_IDLE`},R:null}}},{id:`L22_1`,type:`dialog`,speaker:`MAX_CHARADE_NPC_CAP`,text:{KOREA:`꼼짝 마!!`,JPN:`動くな！！`,ENG:`Freeze!!`,TWN:`全都不准動！！`},stage:{bg:`PROLOGUE_04`,slots:{L:null,C:{char_id:`MAX_CHARADE_NPC_CAP`,face:`UNIT_IDLE`},R:{char_id:`MAX_CHARADE_NPC_MOB`,face:`UNIT_IDLE`}}}},{id:`L23_1`,type:`dialog`,speaker:`MAX_CHARADE_NPC_CAP`,text:{KOREA:`무기를 버리고 머리 위로 손 올려! 너희들은 포위……`,JPN:`武器を捨てて手を頭の上に上げろ！　お前らは包囲……`,ENG:`Drop your weapons and put your hands in the air! You're surr–`,TWN:`放下武器，手舉起來！你們已經被包圍……`},stage:{bg:`PROLOGUE_04`,slots:{L:null,C:{char_id:`MAX_CHARADE_NPC_CAP`,face:`UNIT_IDLE`},R:{char_id:`MAX_CHARADE_NPC_MOB`,face:`UNIT_IDLE`}}}},{id:`L24_1`,type:`dialog`,speaker:`MAX_CHARADE_NPC_CAP`,text:{KOREA:` 응?`,JPN:` あ？`,ENG:`Huh?`,TWN:`嗯？`},stage:{bg:`PROLOGUE_04`,slots:{L:null,C:{char_id:`MAX_CHARADE_NPC_CAP`,face:`UNIT_IDLE`},R:{char_id:`MAX_CHARADE_NPC_MOB`,face:`UNIT_IDLE`}}}},{id:`L26_1`,type:`dialog`,speaker:`STAFF_CANARY_NULL_NULL`,text:{KOREA:`하, 하하…….`,JPN:`こ、ここ……`,ENG:`Ha, haha...`,TWN:`哈哈……`},stage:{bg:`PROLOGUE_04`,slots:{L:null,C:{char_id:`STAFF_CANARY_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L27_1`,type:`dialog`,speaker:`STAFF_CANARY_NULL_NULL`,text:{KOREA:`항복이에요.`,JPN:`降参です。`,ENG:`I surrender.`,TWN:`我投降。`},stage:{bg:`PROLOGUE_04`,slots:{L:null,C:{char_id:`STAFF_CANARY_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L31_1`,type:`dialog`,speaker:`MAX_CHARADE_NPC_CAP`,text:{KOREA:`뭐, 뭐야? 왜 스태프 밖에 없어? 다른 녀석들은……?`,JPN:`な、何だ？　なんでスタッフだけなんだ？　他の奴らは……？`,ENG:`W-what?! Why's there only the staff member? What about the others...?`,TWN:`搞什麼？怎麼只有駕駛員在？其他人呢……？`},stage:{bg:`PROLOGUE_04`,slots:{L:null,C:{char_id:`MAX_CHARADE_NPC_CAP`,face:`UNIT_IDLE`},R:{char_id:`MAX_CHARADE_NPC_MOB`,face:`UNIT_IDLE`}}}},{id:`L32_1`,type:`dialog`,speaker:`MAX_CHARADE_NPC_CAP`,text:{KOREA:`설마!? 이 자식들 처음부터……!?`,JPN:`まさか！？　こいつら、最初から……！？`,ENG:`No way! Was their plan to...?!`,TWN:`難道！？她們打從一開始就……！？`},stage:{bg:`PROLOGUE_04`,slots:{L:null,C:{char_id:`MAX_CHARADE_NPC_CAP`,face:`UNIT_IDLE`},R:{char_id:`MAX_CHARADE_NPC_MOB`,face:`UNIT_IDLE`}}}},{id:`L39_1`,type:`dialog`,speaker:`MAX_CHARADE_NPC_MOB`,text:{KOREA:`잠깐! 이 녀석들 어디서 갑자기 튀어나온 거야!?`,JPN:`おい！　お前たち、いきなりどこから現れた！？`,ENG:`Wait! Where are they coming from?!`,TWN:`等等！她們是從哪裡冒出來的！？`},stage:{bg:`UNDER`,slots:{L:null,C:{char_id:`MAX_CHARADE_NPC_MOB`,face:`UNIT_IDLE`},R:null}}},{id:`L40_1`,type:`dialog`,speaker:`MAX_CHARADE_NPC_MOB`,text:{KOREA:`빨리 대장에게 연락해! 여기가 뚫리면 곧바로 거점이!`,JPN:`早く隊長に連絡しろ！　ここが突破されたら、すぐ拠点が！`,ENG:`Contact the leader now! If they break through here, they'll reach our base!`,TWN:`快通知隊長！這裡被突破的話，再過去就是據點了！`},stage:{bg:`UNDER`,slots:{L:null,C:{char_id:`MAX_CHARADE_NPC_MOB`,face:`UNIT_IDLE`},R:null}}}];export{e as default};